def forward(self, x: Any) -> Any:
    for layer in self.layers:
        attn = layer.self_attn
        # Use all 4 projections so all A/B tensors get gradients
        x = attn.q_proj(x) + attn.k_proj(x) + attn.v_proj(x) + attn.o_proj(x)
    return x
